func (o *Signal) Preload(name string, retrieved any) error {
	if o == nil {
		return nil
	}

	switch name {
	case "AddressorUser":
		rel, ok := retrieved.(*User)
		if !ok {
			return fmt.Errorf("signal cannot load %T as %q", retrieved, name)
		}

		o.R.AddressorUser = rel

		if rel != nil {
			rel.R.AddressorSignals = SignalSlice{o}
		}
		return nil
	case "CreatorUser":
		rel, ok := retrieved.(*User)
		if !ok {
			return fmt.Errorf("signal cannot load %T as %q", retrieved, name)
		}

		o.R.CreatorUser = rel

		if rel != nil {
			rel.R.CreatorSignals = SignalSlice{o}
		}
		return nil
	case "Organization":
		rel, ok := retrieved.(*Organization)
		if !ok {
			return fmt.Errorf("signal cannot load %T as %q", retrieved, name)
		}

		o.R.Organization = rel

		if rel != nil {
			rel.R.Signals = SignalSlice{o}
		}
		return nil
	case "SignalPools":
		rels, ok := retrieved.(SignalPoolSlice)
		if !ok {
			return fmt.Errorf("signal cannot load %T as %q", retrieved, name)
		}

		o.R.SignalPools = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.Signal = o
			}
		}
		return nil
	default:
		return fmt.Errorf("signal has no relationship %q", name)
	}
}

